{
  "name": "Relational Reasoning Trainer",
  "description": "An interactive web application designed to enhance relational reasoning skills. Users can define spatial relationships between objects, and the app uses a vector graph to infer and validate conclusions, providing instant feedback and randomly generated puzzles."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { RelationalEngine } from './services/relationalEngine';
import type { Premise, Conclusion, Analogy, Result, Vector } from './types';
import { generatePuzzle } from './services/puzzleGenerator';
import { PremiseInput } from './components/PremiseInput';
import { ConclusionChecker } from './components/ConclusionChecker';
import { ResultsDisplay } from './components/ResultsDisplay';
import { PremiseList } from './components/PremiseList';
import { Header } from './components/Header';
import { InfoIcon, RefreshCwIcon } from './components/Icons';

const App: React.FC = () => {
    const [engine, setEngine] = useState(() => new RelationalEngine());
    const [premises, setPremises] = useState<Premise[]>([]);
    const [result, setResult] = useState<Result | null>(null);
    const [isAnalogy, setIsAnalogy] = useState(false);

    const resetState = useCallback(() => {
        const newEngine = new RelationalEngine();
        setEngine(newEngine);
        setPremises([]);
        setResult(null);
    }, []);

    const handleGeneratePuzzle = useCallback(() => {
        resetState();
        const { premises: newPremises, conclusion, isAnalogy: puzzleIsAnalogy } = generatePuzzle();
        const newEngine = new RelationalEngine();
        newPremises.forEach(p => newEngine.addRelation(p.itemA, p.direction, p.itemB));
        setEngine(newEngine);
        setPremises(newPremises);
        setIsAnalogy(puzzleIsAnalogy);
    }, [resetState]);

    useEffect(() => {
        handleGeneratePuzzle();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    const handleAddPremise = (premise: Premise) => {
        engine.addRelation(premise.itemA, premise.direction, premise.itemB);
        setPremises(prev => [...prev, premise]);
        setResult(null); 
    };

    const handleRemovePremise = (index: number) => {
        const newPremises = premises.filter((_, i) => i !== index);
        const newEngine = new RelationalEngine();
        newPremises.forEach(p => newEngine.addRelation(p.itemA, p.direction, p.itemB));
        setEngine(newEngine);
        setPremises(newPremises);
        setResult(null);
    };

    const handleCheck = (data: Conclusion | Analogy) => {
        if ('direction' in data) { // It's a Conclusion
            const conclusion = data as Conclusion;
            const vector = engine.getRelativeVector(conclusion.itemB, conclusion.itemA);
            const expectedVector = engine.dirMap.get(conclusion.direction);
            const isCorrect = vector && expectedVector ? vector[0] === expectedVector[0] && vector[1] === expectedVector[1] : false;
            setResult({
                type: 'Conclusion',
                isCorrect,
                actualVector: vector,
                expectedVector,
                text: isCorrect ? 'Conclusion is TRUE' : 'Conclusion is FALSE'
            });
        } else { // It's an Analogy
            const analogy = data as Analogy;
            const vector1 = engine.getRelativeVector(analogy.itemB1, analogy.itemA1);
            const vector2 = engine.getRelativeVector(analogy.itemB2, analogy.itemA2);
            const isCorrect = vector1 && vector2 ? vector1[0] === vector2[0] && vector1[1] === vector2[1] : false;
            setResult({
                type: 'Analogy',
                isCorrect,
                vector1,
                vector2,
                text: isCorrect ? 'Analogy holds TRUE' : 'Analogy is FALSE'
            });
        }
    };

    const allItems = useMemo(() => {
        const items = new Set<string>();
        premises.forEach(p => {
            items.add(p.itemA);
            items.add(p.itemB);
        });
        return Array.from(items);
    }, [premises]);

    return (
        <div className="min-h-screen bg-slate-900 text-slate-200 p-4 sm:p-6 lg:p-8">
            <div className="max-w-4xl mx-auto">
                <Header />
                <div className="mt-6 p-4 sm:p-6 bg-slate-800/50 rounded-lg border border-slate-700 backdrop-blur-sm">
                   <div className="flex justify-between items-center mb-4">
                     <h2 className="text-xl font-bold text-cyan-400">Current Puzzle</h2>
                     <button
                        onClick={handleGeneratePuzzle}
                        className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-md hover:bg-indigo-500 transition-colors duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-900 focus:ring-indigo-500"
                      >
                        <RefreshCwIcon className="w-4 h-4" />
                        New Puzzle
                      </button>
                   </div>
                   <div className="bg-slate-900/50 p-3 rounded-md border border-slate-700 flex items-start gap-3 text-slate-400">
                        <InfoIcon className="w-5 h-5 mt-0.5 text-cyan-400 shrink-0"/>
                        <p>Define relationships between items in the premise list, then form a conclusion or analogy to check if it's logically valid based on the established graph.</p>
                   </div>
                </div>

                <div className="mt-6 grid grid-cols-1 lg:grid-cols-2 gap-6">
                    <div className="space-y-6">
                        <PremiseInput onAddPremise={handleAddPremise} allDirections={engine.getAllDirections()} />
                        <PremiseList premises={premises} onRemovePremise={handleRemovePremise} />
                    </div>
                    <div className="space-y-6">
                        <ConclusionChecker onCheck={handleCheck} allItems={allItems} allDirections={engine.getAllDirections()} isAnalogy={isAnalogy} setIsAnalogy={setIsAnalogy}/>
                        {result && <ResultsDisplay result={result} />}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default App;

export type Vector = [number, number];

export interface Premise {
    itemA: string;
    direction: string;
    itemB: string;
}

export interface Conclusion {
    itemA: string;
    direction: string;
    itemB: string;
}

export interface Analogy {
    itemA1: string;
    itemB1: string;
    itemA2: string;
    itemB2: string;
}

export type Result = {
    type: 'Conclusion';
    isCorrect: boolean;
    actualVector: Vector | null;
    expectedVector: Vector | undefined;
    text: string;
} | {
    type: 'Analogy';
    isCorrect: boolean;
    vector1: Vector | null;
    vector2: Vector | null;
    text: string;
};

import type { Vector } from '../types';

export class RelationalEngine {
    public dirMap: Map<string, Vector>;
    private graph: Map<string, { neighbor: string; vector: Vector }[]>;

    constructor() {
        this.dirMap = new Map([
            ["North", [0, 1]], ["South", [0, -1]],
            ["East", [1, 0]], ["West", [-1, 0]],
            ["North-East", [1, 1]], ["South-East", [1, -1]],
            ["North-West", [-1, 1]], ["South-West", [-1, -1]],
            ["Far North", [0, 2]], ["Far South", [0, -2]],
            ["Far East", [2, 0]], ["Far West", [-2, 0]],
            ["Far North-East", [2, 2]], ["Far South-East", [2, -2]],
            ["Far North-West", [-2, 2]], ["Far South-West", [-2, -2]]
        ]);
        this.graph = new Map();
    }

    public getAllDirections(): string[] {
        return Array.from(this.dirMap.keys());
    }

    public addRelation(itemA: string, direction: string, itemB: string): void {
        const vector = this.dirMap.get(direction);
        if (!vector) return;

        const inverseVector: Vector = [-vector[0], -vector[1]];

        if (!this.graph.has(itemB)) this.graph.set(itemB, []);
        if (!this.graph.has(itemA)) this.graph.set(itemA, []);

        this.graph.get(itemB)!.push({ neighbor: itemA, vector });
        this.graph.get(itemA)!.push({ neighbor: itemB, vector: inverseVector });
    }

    public getRelativeVector(start: string, end: string): Vector | null {
        if (!this.graph.has(start) || !this.graph.has(end)) {
            return null;
        }

        const queue: { node: string; vector: Vector }[] = [{ node: start, vector: [0, 0] }];
        const visited = new Set<string>();
        visited.add(start);

        while (queue.length > 0) {
            const { node: currNode, vector: currVec } = queue.shift()!;

            if (currNode === end) {
                return currVec;
            }

            const neighbors = this.graph.get(currNode) || [];
            for (const { neighbor, vector: vecOffset } of neighbors) {
                if (!visited.has(neighbor)) {
                    visited.add(neighbor);
                    const newVec: Vector = [currVec[0] + vecOffset[0], currVec[1] + vecOffset[1]];
                    queue.push({ node: neighbor, vector: newVec });
                }
            }
        }
        return null;
    }
}

import type { Premise, Conclusion, Analogy } from '../types';

const NODES = ["JEX", "VUL", "MOX", "GEP", "ZAR", "FUM", "KIP", "LUN", "WEX", "QIN"];
const DIRECTIONS = [
    { name: "North", vector: [0, 1] }, { name: "South", vector: [0, -1] },
    { name: "East", vector: [1, 0] }, { name: "West", vector: [-1, 0] },
    { name: "North-East", vector: [1, 1] }, { name: "South-East", vector: [1, -1] },
    { name: "North-West", vector: [-1, 1] }, { name: "South-West", vector: [-1, -1] },
];

function shuffle<T,>(array: T[]): T[] {
    const newArray = [...array];
    for (let i = newArray.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
    }
    return newArray;
}

function getDirectionFromVector(vec: [number, number]): string | null {
    for (const dir of DIRECTIONS) {
        if (dir.vector[0] === vec[0] && dir.vector[1] === vec[1]) {
            return dir.name;
        }
    }
    return null;
}

export const generatePuzzle = (): { premises: Premise[], conclusion: Conclusion | Analogy, isAnalogy: boolean } => {
    const numNodes = 4 + Math.floor(Math.random() * 2); // 4 or 5 nodes
    const puzzleNodes = shuffle(NODES).slice(0, numNodes);

    const coordinates: Map<string, [number, number]> = new Map();
    const premises: Premise[] = [];

    // Place first node at origin
    coordinates.set(puzzleNodes[0], [0, 0]);
    const placedNodes = new Set([puzzleNodes[0]]);
    const unplacedNodes = puzzleNodes.slice(1);

    while (unplacedNodes.length > 0) {
        const nodeToPlace = unplacedNodes.shift()!;
        const referenceNode = shuffle(Array.from(placedNodes))[0];
        const refCoords = coordinates.get(referenceNode)!;

        let newCoords: [number, number];
        let direction: string;

        do {
            const randomDir = DIRECTIONS[Math.floor(Math.random() * DIRECTIONS.length)];
            direction = randomDir.name;
            newCoords = [refCoords[0] + randomDir.vector[0], refCoords[1] + randomDir.vector[1]];
        } while (Array.from(coordinates.values()).some(c => c[0] === newCoords[0] && c[1] === newCoords[1]));

        coordinates.set(nodeToPlace, newCoords);
        placedNodes.add(nodeToPlace);
        premises.push({ itemA: nodeToPlace, direction, itemB: referenceNode });
    }

    // Decide if it's a conclusion or analogy puzzle
    const isAnalogy = Math.random() > 0.5 && numNodes >= 4;

    if (isAnalogy) {
        const fourNodes = shuffle(puzzleNodes).slice(0, 4);
        const [itemB1, itemA1, itemB2, itemA2] = fourNodes;

        const vec1 = [coordinates.get(itemA1)![0] - coordinates.get(itemB1)![0], coordinates.get(itemA1)![1] - coordinates.get(itemB1)![1]];

        // Make it a false analogy 50% of the time
        if (Math.random() > 0.5) {
             const conclusion: Analogy = { itemA1, itemB1, itemA2, itemB2 };
             return { premises: shuffle(premises), conclusion, isAnalogy: true };
        } else {
            // Find a pair with the same vector
             for (let i = 0; i < puzzleNodes.length; i++) {
                for (let j = 0; j < puzzleNodes.length; j++) {
                    if (i === j) continue;
                    const nodeA = puzzleNodes[i];
                    const nodeB = puzzleNodes[j];
                    if ([itemA1, itemB1].includes(nodeA) || [itemA1, itemB1].includes(nodeB)) continue;

                    const vec2 = [coordinates.get(nodeA)![0] - coordinates.get(nodeB)![0], coordinates.get(nodeA)![1] - coordinates.get(nodeB)![1]];
                    if (vec1[0] === vec2[0] && vec1[1] === vec2[1]) {
                         const conclusion: Analogy = { itemA1, itemB1, itemA2: nodeA, itemB2: nodeB };
                         return { premises: shuffle(premises), conclusion, isAnalogy: true };
                    }
                }
            }
        }
        // Fallback to conclusion if no analogy found
    }

    // Generate Conclusion
    const [itemB, itemA] = shuffle(puzzleNodes).slice(0, 2);
    const vec = [coordinates.get(itemA)![0] - coordinates.get(itemB)![0], coordinates.get(itemA)![1] - coordinates.get(itemB)![1]];
    let conclusionDirection = getDirectionFromVector(vec as [number, number]);

    // Make it a false conclusion 50% of the time
    if (Math.random() > 0.5 || !conclusionDirection) {
        const allDirs = DIRECTIONS.map(d => d.name);
        conclusionDirection = shuffle(allDirs).find(d => d !== conclusionDirection) || "North";
    }

    const conclusion: Conclusion = { itemA, direction: conclusionDirection, itemB };

    return { premises: shuffle(premises), conclusion, isAnalogy: false };
};

import React from 'react';
import { BrainCircuitIcon } from './Icons';

export const Header: React.FC = () => {
    return (
        <header className="text-center">
            <div className="inline-flex items-center gap-3">
                <BrainCircuitIcon className="w-10 h-10 text-cyan-400" />
                <h1 className="text-4xl font-bold text-white tracking-tight">
                    Relational Reasoning Trainer
                </h1>
            </div>
            <p className="mt-2 text-lg text-slate-400 max-w-2xl mx-auto">
                Build a mental map from premises, then test your logical deductions.
            </p>
        </header>
    );
};

import React, { useState } from 'react';
import type { Premise } from '../types';
import { PlusIcon } from './Icons';

interface PremiseInputProps {
    onAddPremise: (premise: Premise) => void;
    allDirections: string[];
}

export const PremiseInput: React.FC<PremiseInputProps> = ({ onAddPremise, allDirections }) => {
    const [itemA, setItemA] = useState('');
    const [itemB, setItemB] = useState('');
    const [direction, setDirection] = useState(allDirections[0]);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (itemA.trim() && itemB.trim() && direction) {
            onAddPremise({ 
                itemA: itemA.trim().toUpperCase(), 
                direction, 
                itemB: itemB.trim().toUpperCase() 
            });
            setItemA('');
            setItemB('');
        }
    };

    return (
        <div className="p-4 bg-slate-800/50 rounded-lg border border-slate-700">
            <h3 className="text-lg font-semibold text-cyan-400 mb-3">Add Premise</h3>
            <form onSubmit={handleSubmit} className="space-y-3">
                <div className="flex items-center gap-2">
                    <input
                        type="text"
                        value={itemA}
                        onChange={(e) => setItemA(e.target.value)}
                        placeholder="Item A"
                        maxLength={3}
                        className="font-space-mono w-full px-3 py-2 bg-slate-900 border border-slate-600 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500 placeholder-slate-500"
                    />
                    <span className="text-slate-400">is</span>
                    <select
                        value={direction}
                        onChange={(e) => setDirection(e.target.value)}
                        className="w-full px-3 py-2 bg-slate-900 border border-slate-600 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500"
                    >
                        {allDirections.map(dir => <option key={dir} value={dir}>{dir}</option>)}
                    </select>
                     <span className="text-slate-400">of</span>
                </div>
                 <input
                    type="text"
                    value={itemB}
                    onChange={(e) => setItemB(e.target.value)}
                    placeholder="Item B"
                    maxLength={3}
                    className="font-space-mono w-full px-3 py-2 bg-slate-900 border border-slate-600 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500 placeholder-slate-500"
                />
                <button
                    type="submit"
                    className="w-full flex items-center justify-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-md hover:bg-indigo-500 transition-colors duration-200 disabled:bg-slate-600 disabled:cursor-not-allowed"
                    disabled={!itemA.trim() || !itemB.trim()}
                >
                    <PlusIcon className="w-4 h-4" />
                    Add Premise
                </button>
            </form>
        </div>
    );
};

import React from 'react';
import type { Premise } from '../types';
import { ListIcon, XIcon } from './Icons';

interface PremiseListProps {
    premises: Premise[];
    onRemovePremise: (index: number) => void;
}

export const PremiseList: React.FC<PremiseListProps> = ({ premises, onRemovePremise }) => {
    return (
        <div className="p-4 bg-slate-800/50 rounded-lg border border-slate-700">
            <h3 className="text-lg font-semibold text-cyan-400 mb-3 flex items-center gap-2"><ListIcon className="w-5 h-5"/>Premise List</h3>
            <div className="space-y-2 max-h-60 overflow-y-auto pr-2">
                {premises.length === 0 ? (
                    <p className="text-slate-500 text-center py-4">No premises added yet.</p>
                ) : (
                    premises.map((p, index) => (
                        <div key={index} className="flex items-center justify-between bg-slate-900/70 p-2 rounded-md">
                            <p className="font-space-mono text-slate-300">
                                <span className="text-yellow-400">{p.itemA}</span> is <span className="text-purple-400">{p.direction}</span> of <span className="text-yellow-400">{p.itemB}</span>
                            </p>
                            <button onClick={() => onRemovePremise(index)} className="text-slate-500 hover:text-red-500 transition-colors">
                                <XIcon className="w-4 h-4" />
                            </button>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
};

import React, { useState } from 'react';
import type { Conclusion, Analogy } from '../types';
import { CheckCircleIcon } from './Icons';

interface ConclusionCheckerProps {
    onCheck: (data: Conclusion | Analogy) => void;
    allItems: string[];
    allDirections: string[];
    isAnalogy: boolean;
    setIsAnalogy: (isAnalogy: boolean) => void;
}

export const ConclusionChecker: React.FC<ConclusionCheckerProps> = ({ onCheck, allItems, allDirections, isAnalogy, setIsAnalogy }) => {
    const [itemA, setItemA] = useState('');
    const [itemB, setItemB] = useState('');
    const [direction, setDirection] = useState(allDirections[0]);

    const [itemA1, setItemA1] = useState('');
    const [itemB1, setItemB1] = useState('');
    const [itemA2, setItemA2] = useState('');
    const [itemB2, setItemB2] = useState('');

    const handleCheck = () => {
        if (isAnalogy) {
             if (itemA1 && itemB1 && itemA2 && itemB2) {
                onCheck({ itemA1, itemB1, itemA2, itemB2 });
            }
        } else {
             if (itemA && itemB && direction) {
                onCheck({ itemA, direction, itemB });
            }
        }
    };

    const canCheckConclusion = itemA && itemB && direction && allItems.includes(itemA) && allItems.includes(itemB);
    const canCheckAnalogy = itemA1 && itemB1 && itemA2 && itemB2 && [itemA1, itemB1, itemA2, itemB2].every(item => allItems.includes(item));

    return (
        <div className="p-4 bg-slate-800/50 rounded-lg border border-slate-700">
            <div className="flex justify-between items-center mb-3">
                <h3 className="text-lg font-semibold text-cyan-400">Validate</h3>
                <div className="flex items-center gap-2 text-sm bg-slate-900 border border-slate-700 p-1 rounded-md">
                    <button onClick={() => setIsAnalogy(false)} className={`px-2 py-1 rounded ${!isAnalogy ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:bg-slate-700'}`}>Conclusion</button>
                    <button onClick={() => setIsAnalogy(true)} className={`px-2 py-1 rounded ${isAnalogy ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:bg-slate-700'}`}>Analogy</button>
                </div>
            </div>

            {isAnalogy ? (
                <div className="space-y-3">
                    <p className="text-slate-400 text-center">
                        <span className="font-space-mono text-yellow-400">{itemA1 || '?'}</span> to <span className="font-space-mono text-yellow-400">{itemB1 || '?'}</span> is like <span className="font-space-mono text-yellow-400">{itemA2 || '?'}</span> to <span className="font-space-mono text-yellow-400">{itemB2 || '?'}</span>
                    </p>
                    <div className="grid grid-cols-2 gap-3">
                        <ItemSelector label="Item A1" value={itemA1} onChange={setItemA1} items={allItems} />
                        <ItemSelector label="Item B1" value={itemB1} onChange={setItemB1} items={allItems} />
                        <ItemSelector label="Item A2" value={itemA2} onChange={setItemA2} items={allItems} />
                        <ItemSelector label="Item B2" value={itemB2} onChange={setItemB2} items={allItems} />
                    </div>
                </div>
            ) : (
                <div className="space-y-3">
                     <p className="text-slate-400 text-center">
                        Is <span className="font-space-mono text-yellow-400">{itemA || '?'}</span> <span className="font-space-mono text-purple-400">{direction || '?'}</span> of <span className="font-space-mono text-yellow-400">{itemB || '?'}</span>?
                    </p>
                    <div className="grid grid-cols-2 gap-3">
                        <ItemSelector label="Item A" value={itemA} onChange={setItemA} items={allItems} />
                        <ItemSelector label="Item B" value={itemB} onChange={setItemB} items={allItems} />
                    </div>
                    <select
                        value={direction}
                        onChange={(e) => setDirection(e.target.value)}
                        className="w-full px-3 py-2 bg-slate-900 border border-slate-600 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500"
                    >
                        {allDirections.map(dir => <option key={dir} value={dir}>{dir}</option>)}
                    </select>
                </div>
            )}

            <button
                onClick={handleCheck}
                className="w-full mt-4 flex items-center justify-center gap-2 px-4 py-2 bg-green-600 text-white rounded-md hover:bg-green-500 transition-colors duration-200 disabled:bg-slate-600 disabled:cursor-not-allowed"
                disabled={isAnalogy ? !canCheckAnalogy : !canCheckConclusion}
            >
                <CheckCircleIcon className="w-5 h-5"/>
                Check
            </button>
        </div>
    );
};

const ItemSelector: React.FC<{label: string, value: string, onChange: (val: string) => void, items: string[]}> = ({label, value, onChange, items}) => {
    return (
        <div>
            <label className="text-sm text-slate-400 block mb-1">{label}</label>
            <select
                value={value}
                onChange={(e) => onChange(e.target.value)}
                className="font-space-mono w-full px-3 py-2 bg-slate-900 border border-slate-600 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500"
            >
                <option value="">Select</option>
                {items.map(item => <option key={item} value={item}>{item}</option>)}
            </select>
        </div>
    )
}

import React from 'react';
import type { Result, Vector } from '../types';
import { CheckIcon, XIcon, ArrowRightIcon } from './Icons';

interface ResultsDisplayProps {
    result: Result;
}

const formatVector = (v: Vector | null | undefined): string => {
    if (!v) return 'N/A';
    return `[${v[0]}, ${v[1]}]`;
};

export const ResultsDisplay: React.FC<ResultsDisplayProps> = ({ result }) => {
    const isCorrect = result.isCorrect;

    return (
        <div className={`p-4 rounded-lg border ${isCorrect ? 'bg-green-900/30 border-green-500/50' : 'bg-red-900/30 border-red-500/50'}`}>
            <div className="flex items-center gap-3">
                {isCorrect ? <CheckIcon className="w-6 h-6 text-green-400" /> : <XIcon className="w-6 h-6 text-red-400" />}
