export type Vector = [number, number];
export type GameState = 'idle' | 'playing' | 'gameOver';

export interface Premise {
    itemA: string;
    direction: string;
    itemB: string;
}

export interface Conclusion {
    itemA: string;
    direction: string;
    itemB: string;
}

export interface Analogy {
    itemA1: string;
    itemB1: string;
    itemA2: string;
    itemB2: string;
