export type Vector = [number, number];
export type GameState = 'idle' | 'playing' | 'gameOver' | 'settings';
export type GameOverReason = 'time' | 'rounds' | 'quit';

export interface Premise {
    itemA: string;
    direction: string;
    itemB: string;
}

export interface Conclusion {
    itemA: string;
    direction: string;
    itemB: string;
}

export interface Analogy {
    itemA1: string;
    itemB1: string;
    itemA2: string;
    itemB2: string;
}

export type Challenge = {
    type: 'conclusion';
    statement: Conclusion;
    isTrue: boolean;
} | {
    type: 'analogy';
    statement: Analogy;
    isTrue: boolean;
};

export type Result = {
    type: 'Conclusion';
    isCorrect: boolean;
    actualVector: Vector | null;
    expectedVector: Vector | undefined;
    text: string;
} | {
    type: 'Analogy';
    isCorrect: boolean;
    vector1: Vector | null;
    vector2: Vector | null;
    text: string;
};

import type { Premise, Conclusion, Vector, Analogy, Challenge } from '../types';

const NODES = ["JEX", "VUL", "MOX", "GEP", "ZAR", "FUM", "KIP", "LUN", "WEX", "QIN", "BIX", "DAK", "ROV", "SAJ"];
const DIRECTIONS: { name: string, vector: Vector }[] = [
    { name: "North", vector: [0, 1] }, { name: "South", vector: [0, -1] },
    { name: "East", vector: [1, 0] }, { name: "West", vector: [-1, 0] },
    { name: "North-East", vector: [1, 1] }, { name: "South-East", vector: [1, -1] },
    { name: "North-West", vector: [-1, 1] }, { name: "South-West", vector: [-1, -1] },
];

function shuffle<T,>(array: T[]): T[] {
    const newArray = [...array];
    for (let i = newArray.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
    }
    return newArray;
}

function getDirectionFromVector(vec: Vector): string | null {
    for (const dir of DIRECTIONS) {
        if (dir.vector[0] === vec[0] && dir.vector[1] === vec[1]) {
            return dir.name;
        }
    }
    return null;
}

function usesSameItemsAsPremise(conclusion: Conclusion, premise: Premise | null): boolean {
    if (!premise) return false;
    const conclusionItems = [conclusion.itemA, conclusion.itemB].sort();
    const premiseItems = [premise.itemA, premise.itemB].sort();
    return conclusionItems[0] === premiseItems[0] && conclusionItems[1] === premiseItems[1];
}

function createConclusion(nodes: string[], coordinates: Map<string, Vector>, latestNode: string | null = null, lastPremise: Premise | null = null): { statement: Conclusion, isTrue: boolean } {
    let statement: Conclusion;
    let isTrue: boolean;

    do {
        let itemA, itemB;
        const useLatestNode = latestNode && Math.random() < 0.25;
        if (useLatestNode) {
            itemA = latestNode!;
            itemB = shuffle(nodes.filter(n => n !== latestNode))[0];
            if (Math.random() > 0.5) [itemA, itemB] = [itemB, itemA];
        } else {
            const olderNodes = latestNode ? nodes.filter(n => n !== latestNode) : nodes;
            const nodePool = olderNodes.length >= 2 ? olderNodes : nodes;
            [itemB, itemA] = shuffle(nodePool).slice(0, 2);
        }

        const vec: Vector = [coordinates.get(itemA)![0] - coordinates.get(itemB)![0], coordinates.get(itemA)![1] - coordinates.get(itemB)![1]];
        const actualDirection = getDirectionFromVector(vec);
        const shouldBeTrue = Math.random() > 0.4;

        if (shouldBeTrue && actualDirection) {
            statement = { itemA, direction: actualDirection, itemB };
            isTrue = true;
        } else {
            const allDirs = DIRECTIONS.map(d => d.name);
            const falseDirection = shuffle(allDirs).find(d => d !== actualDirection) || "North";
            statement = { itemA, direction: falseDirection, itemB };
            isTrue = false;
        }
    } while (usesSameItemsAsPremise(statement, lastPremise));

    return { statement, isTrue };
}

function createAnalogy(nodes: string[], coordinates: Map<string, Vector>): { statement: Analogy, isTrue: boolean } {
    const isTrue = Math.random() > 0.5;
    let statement: Analogy;

    if (isTrue) {
        const vectors: Map<string, [string, string][]> = new Map();
        for (let i = 0; i < nodes.length; i++) {
            for (let j = 0; j < nodes.length; j++) {
                if (i === j) continue;
                const itemA = nodes[i];
                const itemB = nodes[j];
                const vec: Vector = [coordinates.get(itemA)![0] - coordinates.get(itemB)![0], coordinates.get(itemA)![1] - coordinates.get(itemB)![1]];
                const vecKey = vec.toString();
                if (!vectors.has(vecKey)) vectors.set(vecKey, []);
                vectors.get(vecKey)!.push([itemA, itemB]);
            }
        }
        const validPairs = Array.from(vectors.values()).filter(v => v.length >= 2);

        if (validPairs.length > 0) {
            const pairSet = shuffle(validPairs)[0];
            const [[itemA1, itemB1], [itemA2, itemB2]] = shuffle(pairSet).slice(0, 2);
            statement = { itemA1, itemB1, itemA2, itemB2 };
            return { statement, isTrue: true };
        }
    }

    let [itemA1, itemB1, itemA2, itemB2] = shuffle(nodes).slice(0, 4);
    let vec1: Vector, vec2: Vector;
    do {
        [itemA1, itemB1, itemA2, itemB2] = shuffle(nodes).slice(0, 4);
        vec1 = [coordinates.get(itemA1)![0] - coordinates.get(itemB1)![0], coordinates.get(itemA1)![1] - coordinates.get(itemB1)![1]];
        vec2 = [coordinates.get(itemA2)![0] - coordinates.get(itemB2)![0], coordinates.get(itemA2)![1] - coordinates.get(itemB2)![1]];
    } while (vec1[0] === vec2[0] && vec1[1] === vec2[1]);

    statement = { itemA1, itemB1, itemA2, itemB2 };
    return { statement, isTrue: false };
}

export const generateInitialPuzzle = (numNodes: number = 5): { premises: Premise[], challenge: Challenge, coordinates: Map<string, Vector>, nodes: string[] } => {
    const puzzleNodes = shuffle(NODES).slice(0, numNodes);
    const coordinates: Map<string, Vector> = new Map();
    const premises: Premise[] = [];

    coordinates.set(puzzleNodes[0], [0, 0]);
    const placedNodes = new Set([puzzleNodes[0]]);
    const unplacedNodes = puzzleNodes.slice(1);

    while (unplacedNodes.length > 0) {
        const nodeToPlace = unplacedNodes.shift()!;
        const referenceNode = shuffle(Array.from(placedNodes))[0];
        const refCoords = coordinates.get(referenceNode)!;
        let newCoords: Vector, direction: string;
        do {
            const randomDir = DIRECTIONS[Math.floor(Math.random() * DIRECTIONS.length)];
            direction = randomDir.name;
            newCoords = [refCoords[0] + randomDir.vector[0], refCoords[1] + randomDir.vector[1]];
        } while (Array.from(coordinates.values()).some(c => c[0] === newCoords[0] && c[1] === newCoords[1]));
        coordinates.set(nodeToPlace, newCoords);
        placedNodes.add(nodeToPlace);
        premises.push({ itemA: nodeToPlace, direction, itemB: referenceNode });
    }

    const challengeType = Math.random() < 0.5 ? 'conclusion' : 'analogy';
    let challenge: Challenge;
    if (challengeType === 'conclusion' || puzzleNodes.length < 4) {
        const { statement, isTrue } = createConclusion(puzzleNodes, coordinates);
        challenge = { type: 'conclusion', statement, isTrue };
    } else {
        const { statement, isTrue } = createAnalogy(puzzleNodes, coordinates);
        challenge = { type: 'analogy', statement, isTrue };
    }

    return { premises, challenge, coordinates, nodes: puzzleNodes };
};

export const advancePuzzle = (currentNodes: string[], currentCoords: Map<string, Vector>) => {
    const nodes = [...currentNodes];
    const coordinates = new Map(currentCoords);

    const oldestNode = nodes.shift()!;
    coordinates.delete(oldestNode);

    const newNode = shuffle(NODES).find(n => !nodes.includes(n) && n !== oldestNode)!;
    const referenceNode = shuffle(nodes)[0];
    const refCoords = coordinates.get(referenceNode)!;
    let newCoords: Vector, direction: string;
    do {
        const randomDir = DIRECTIONS[Math.floor(Math.random() * DIRECTIONS.length)];
        direction = randomDir.name;
        newCoords = [refCoords[0] + randomDir.vector[0], refCoords[1] + randomDir.vector[1]];
    } while (Array.from(coordinates.values()).some(c => c[0] === newCoords[0] && c[1] === newCoords[1]));

    const newPremise: Premise = { itemA: newNode, direction, itemB: referenceNode };
    nodes.push(newNode);
    coordinates.set(newNode, newCoords);

    const challengeType = Math.random() < 0.5 ? 'conclusion' : 'analogy';
    let newChallenge: Challenge;

    if (challengeType === 'conclusion' || nodes.length < 4) {
        const { statement, isTrue } = createConclusion(nodes, coordinates, newNode, newPremise);
        newChallenge = { type: 'conclusion', statement, isTrue };
    } else {
        const { statement, isTrue } = createAnalogy(nodes, coordinates);
        newChallenge = { type: 'analogy', statement, isTrue };
    }

    return { newPremise, newChallenge, updatedNodes: nodes, updatedCoordinates: coordinates, oldestNode };
};

import React, { useState, useEffect, useCallback } from 'react';
import { RelationalEngine } from './services/relationalEngine';
import type { GameState, Premise, Vector, GameOverReason, Challenge } from './types';
import { generateInitialPuzzle, advancePuzzle } from './services/puzzleGenerator';
import StartScreen from './components/StartScreen';
import GameScreen from './components/GameScreen';
import GameOverScreen from './components/GameOverScreen';
import SettingsScreen from './components/SettingsScreen';

const App: React.FC = () => {
    const [gameState, setGameState] = useState<GameState>('idle');
    const [score, setScore] = useState(0);
    const [timeLeft, setTimeLeft] = useState(30);
    const [currentRound, setCurrentRound] = useState(1);
    const [gameOverReason, setGameOverReason] = useState<GameOverReason>('time');

    const [settings, setSettings] = useState({
        initialPremises: 5,
        initialTime: 30,
        totalRounds: 10,
    });

    const [engine, setEngine] = useState(() => new RelationalEngine());
    const [currentChallenge, setCurrentChallenge] = useState<Challenge | null>(null);
    const [puzzleState, setPuzzleState] = useState<{ nodes: string[]; coordinates: Map<string, Vector> } | null>(null);
    const [lastPremise, setLastPremise] = useState<Premise | null>(null);
    const [initialPremises, setInitialPremises] = useState<Premise[] | null>(null);
    const [feedback, setFeedback] = useState<'correct' | 'incorrect' | null>(null);

    useEffect(() => {
        if (gameState !== 'playing' || feedback) return;
        if (timeLeft <= 0) {
            setGameOverReason('time');
            setGameState('gameOver');
            return;
        }
        const timer = setInterval(() => setTimeLeft(t => t - 1), 1000);
        return () => clearInterval(timer);
    }, [gameState, timeLeft, feedback]);

    const handleStart = useCallback(() => {
        const initialPuzzle = generateInitialPuzzle(settings.initialPremises);
        const newEngine = new RelationalEngine();
        initialPuzzle.premises.forEach(p => newEngine.addRelation(p.itemA, p.direction, p.itemB));

        setEngine(newEngine);
        setPuzzleState({ nodes: initialPuzzle.nodes, coordinates: initialPuzzle.coordinates });
        setCurrentChallenge(initialPuzzle.challenge);
        setLastPremise(null); 
        setInitialPremises(initialPuzzle.premises);
        setTimeLeft(settings.initialTime);
        setScore(0);
        setCurrentRound(1);
        setGameState('playing');
        setFeedback(null);
    }, [settings]);

    const handleAnswer = useCallback((userAnswer: boolean) => {
        if (!currentChallenge || !puzzleState) return;

        let isActuallyTrue: boolean;
        if (currentChallenge.type === 'conclusion') {
            const { itemA, itemB, direction } = currentChallenge.statement;
            const vector = engine.getRelativeVector(itemB, itemA);
            const expectedVector = engine.dirMap.get(direction);
            isActuallyTrue = !!(vector && expectedVector && vector[0] === expectedVector[0] && vector[1] === expectedVector[1]);
        } else {
            const { itemA1, itemB1, itemA2, itemB2 } = currentChallenge.statement;
            const vector1 = engine.getRelativeVector(itemB1, itemA1);
            const vector2 = engine.getRelativeVector(itemB2, itemA2);
            isActuallyTrue = !!(vector1 && vector2 && vector1[0] === vector2[0] && vector1[1] === vector2[1]);
        }

        const wasCorrect = userAnswer === isActuallyTrue;
        setFeedback(wasCorrect ? 'correct' : 'incorrect');

        if (wasCorrect) {
            setScore(s => s + 10);
            setTimeLeft(t => t + 10);
        } else {
            setTimeLeft(t => Math.max(0, t - 10));
        }

        setTimeout(() => {
            if (wasCorrect && currentRound >= settings.totalRounds) {
                setGameOverReason('rounds');
                setGameState('gameOver');
                return;
            }

            const nextStep = advancePuzzle(puzzleState.nodes, puzzleState.coordinates);
            const newEngine = new RelationalEngine();
            const allNodes = nextStep.updatedNodes;
            const allCoords = nextStep.updatedCoordinates;

            for (const node1 of allNodes) {
                for (const node2 of allNodes) {
                    if (node1 === node2) continue;
                    const coord1 = allCoords.get(node1)!;
                    const coord2 = allCoords.get(node2)!;
                    const vec: Vector = [coord1[0] - coord2[0], coord1[1] - coord2[1]];
                    for (const [dir, dirVec] of engine.dirMap.entries()) {
                        if (vec[0] === dirVec[0] && vec[1] === dirVec[1]) {
                             newEngine.addRelation(node1, dir, node2);
                        }
                    }
                }
            }

            setEngine(newEngine);
            setPuzzleState({ nodes: nextStep.updatedNodes, coordinates: nextStep.updatedCoordinates });
            setCurrentChallenge(nextStep.newChallenge);
            setLastPremise(nextStep.newPremise);
            if (wasCorrect) setCurrentRound(r => r + 1);
            setFeedback(null);
        }, 800);

    }, [currentChallenge, puzzleState, engine, currentRound, settings.totalRounds]);

    const handleQuit = () => {
        setGameOverReason('quit');
        setGameState('gameOver');
    };

    const handleGoToMenu = () => setGameState('idle');
    const handleSaveSettings = (newSettings: typeof settings) => {
        setSettings(newSettings);
        setGameState('idle');
    };

    const renderContent = () => {
        switch (gameState) {
            case 'settings':
                return <SettingsScreen currentSettings={settings} onSave={handleSaveSettings} />;
            case 'playing':
                return <GameScreen
                    score={score}
                    timeLeft={timeLeft}
                    challenge={currentChallenge}
                    onAnswer={handleAnswer}
                    feedback={feedback}
                    lastPremise={lastPremise}
                    initialPremises={lastPremise === null ? initialPremises : null}
                    onQuit={handleQuit}
                    currentRound={currentRound}
                    totalRounds={settings.totalRounds}
                />;
            case 'gameOver':
                return <GameOverScreen score={score} onGoToMenu={handleGoToMenu} reason={gameOverReason} />;
            case 'idle':
            default:
                return <StartScreen onStart={handleStart} onShowSettings={() => setGameState('settings')} />;
        }
    };

    return (
        <div className="min-h-screen bg-slate-900 text-slate-200 p-4 sm:p-6 lg:p-8 flex items-center justify-center">
            <div className="w-full max-w-2xl mx-auto relative">
                {renderContent()}
            </div>
        </div>
    );
};

export default App;

import React from 'react';
import type { Premise, Challenge } from '../types';
import { TimerIcon, CheckIcon, XIcon, StarIcon, LogOutIcon } from './Icons';

interface GameScreenProps {
    score: number;
    timeLeft: number;
    challenge: Challenge | null;
    onAnswer: (isTrue: boolean) => void;
    feedback: 'correct' | 'incorrect' | null;
    lastPremise: Premise | null;
    initialPremises: Premise[] | null;
    onQuit: () => void;
    currentRound: number;
    totalRounds: number;
}

const GameScreen: React.FC<GameScreenProps> = ({ score, timeLeft, challenge, onAnswer, feedback, lastPremise, initialPremises, onQuit, currentRound, totalRounds }) => {
    const timerColor = timeLeft <= 10 ? 'text-red-500' : timeLeft <= 20 ? 'text-yellow-400' : 'text-cyan-400';

    const renderChallenge = () => {
        if (!challenge) return null;

        if (challenge.type === 'conclusion') {
            const { itemA, direction, itemB } = challenge.statement;
            return (
                <div className="mt-2 text-2xl font-space-mono text-slate-100 p-4 bg-slate-900/50 rounded-lg border-2 border-dashed border-slate-600">
                    Is <span className="text-yellow-400">{itemA}</span> <span className="text-purple-400">{direction}</span> of <span className="text-yellow-400">{itemB}</span>?
                </div>
            );
        }

        if (challenge.type === 'analogy') {
            const { itemA1, itemB1, itemA2, itemB2 } = challenge.statement;
            return (
                <div className="mt-2 text-xl sm:text-2xl font-space-mono text-slate-100 p-4 bg-slate-900/50 rounded-lg border-2 border-dashed border-slate-600">
                    Is the relation of <span className="text-yellow-400">{itemA1}</span> to <span className="text-yellow-400">{itemB1}</span>
                    <br />
                    the same as <span className="text-yellow-400">{itemA2}</span> to <span className="text-yellow-400">{itemB2}</span>?
                </div>
            );
        }
        return null;
    };

    return (
        <div className="p-6 bg-slate-800/50 rounded-lg border border-slate-700 w-full animate-fade-in relative">
            <button onClick={onQuit} className="absolute top-4 left-4 text-slate-500 hover:text-red-500 transition-colors" aria-label="Quit Game">
                <LogOutIcon className="w-6 h-6" />
            </button>

            <div className="flex justify-between items-center pb-4 border-b border-slate-700">
                <div className="flex items-center gap-2 text-2xl font-bold">
                    <StarIcon className="w-6 h-6 text-yellow-400" />
                    <span>{score}</span>
                </div>
                 <div className="font-bold text-slate-400">
                    Round {currentRound} <span className="text-xs">/ {totalRounds}</span>
                </div>
                <div className={`flex items-center gap-2 text-2xl font-bold ${timerColor}`}>
                    <TimerIcon className="w-6 h-6" />
                    <span>{timeLeft}</span>
                </div>
            </div>

            <div className="mt-6 text-center">
                {initialPremises ? (
                    <>
                        <h2 className="text-slate-400 text-lg">Memorize the starting map:</h2>
                        <div className="mt-2 space-y-2 text-xl font-space-mono text-slate-100 p-4 bg-slate-900/50 rounded-lg animate-pop-in">
                           {initialPremises.map((p, i) => (
                               <p key={`${p.itemA}-${p.itemB}-${i}`}>
                                   <span className="text-yellow-400">{p.itemA}</span> is <span className="text-purple-400">{p.direction}</span> of <span className="text-yellow-400">{p.itemB}</span>
                               </p>
                           ))}
                        </div>
                    </>
                ) : lastPremise && (
                     <>
                        <h2 className="text-slate-400 text-lg">The map has changed:</h2>
                        <div key={`${lastPremise.itemA}-${lastPremise.itemB}`} className="mt-2 text-2xl font-space-mono text-slate-100 p-4 bg-slate-900/50 rounded-lg animate-pop-in">
                            <span className="text-yellow-400">{lastPremise.itemA}</span> is <span className="text-purple-400">{lastPremise.direction}</span> of <span className="text-yellow-400">{lastPremise.itemB}</span>
                        </div>
                     </>
                )}
            </div>

            <div className="mt-8 text-center">
                <h2 className="text-slate-400 text-lg">Based on the current map...</h2>
                {renderChallenge()}
            </div>

            <div className="mt-8 grid grid-cols-2 gap-4">
                 <button 
                    onClick={() => onAnswer(true)} 
                    disabled={!!feedback}
                    className="flex items-center justify-center gap-3 text-2xl font-bold py-4 rounded-lg bg-green-600 text-white hover:bg-green-500 transition-all transform hover:scale-105 disabled:opacity-50 disabled:cursor-not-allowed disabled:scale-100"
                 >
                    <CheckIcon className="w-7 h-7" /> TRUE
                 </button>
                 <button 
                    onClick={() => onAnswer(false)}
                    disabled={!!feedback}
                    className="flex items-center justify-center gap-3 text-2xl font-bold py-4 rounded-lg bg-red-600 text-white hover:bg-red-500 transition-all transform hover:scale-105 disabled:opacity-50 disabled:cursor-not-allowed disabled:scale-100"
                >
                    <XIcon className="w-7 h-7" /> FALSE
                </button>
            </div>

            {feedback && (
                 <div className={`absolute inset-0 bg-slate-800/80 backdrop-blur-sm flex items-center justify-center rounded-lg animate-pop-in`}>
                     {feedback === 'correct' ? <CheckIcon className="w-32 h-32 text-green-400"/> : <XIcon className="w-32 h-32 text-red-400"/> }
                 </div>
            )}
        </div>
    );
};

