                        type="range"
                        min="15"
                        max="60"
                        step="5"
                        value={settings.initialTime}
                        onChange={(e) => setSettings(s => ({ ...s, initialTime: Number(e.target.value) }))}
                        className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-indigo-500"
