                                    settings.challengeType === type 
                                    ? 'bg-indigo-500 text-white' 
                                    : 'bg-transparent text-slate-300 hover:bg-slate-600'
                                }`}
                            >
                                {type === 'conclusions' ? 'Conclusion' : type}
